r_ktm_sakol_req_form_02_nest_fee.sql:
SELECT sc_lon_m_ucf_fee.fee_name as fee_des , sc_lon_m_req_fee.fee_amount as fee_amount FROM sc_lon_m_req_fee, sc_lon_m_ucf_fee WHERE sc_lon_m_ucf_fee.fee_type = sc_lon_m_req_fee.fee_type and sc_lon_m_req_fee.loan_requestment_no = {0}
union
SELECT 'ประกันฯ' as fee_des , sc_lon_m_req_insur.int_force as fee_amount FROM sc_lon_m_req_insur WHERE sc_lon_m_req_insur.loan_requestment_no = {0}
union
SELECT 'ซื้อหุ้น' as fee_des , sc_lon_m_loan_request.buy_share as fee_amount FROM sc_lon_m_loan_request WHERE sc_lon_m_loan_request.buy_share > 0 and sc_lon_m_loan_request.loan_requestment_no = {0}
union
SELECT 'หนี้เดิม' as fee_des , sc_lon_m_loan_request.total_old_loan + sc_lon_m_loan_request.total_oldint as fee_amount FROM sc_lon_m_loan_request WHERE ( sc_lon_m_loan_request.total_old_loan > 0 or sc_lon_m_loan_request.total_oldint > 0 ) and sc_lon_m_loan_request.loan_requestment_no = {0}
